-- 03_updated_initial_script.sql
--
-- Snapshot of the current riftbound database as of 2026-06-24, generated from the live
-- Aspire-managed Postgres instance. This does NOT replace 001_initial_online_battles.sql or
-- 002_card_effect_steps.sql -- it captures the schema additions and card content that have
-- landed since (lobbies/lobby_players/user_active_decks tables, the EffectsJson column, and the
-- hand-authored card effects for the Spell-card pass). Safe to run against a fresh database or
-- one already seeded by 001/002: every statement is idempotent (CREATE TABLE IF NOT EXISTS,
-- ADD COLUMN IF NOT EXISTS, INSERT ... ON CONFLICT DO UPDATE).

-- Tables introduced after 001 (created by EF Core's EnsureCreated rather than a tracked migration).

CREATE TABLE IF NOT EXISTS lobbies (
    "Id" text PRIMARY KEY,
    "HostUserId" text NOT NULL,
    "Name" text NOT NULL,
    "Status" text NOT NULL,
    "AllowedModesJson" jsonb NOT NULL,
    "SelectedMode" text NOT NULL,
    "MaxPlayers" integer NOT NULL,
    "CreatedAt" timestamptz NOT NULL,
    "UpdatedAt" timestamptz NOT NULL,
    "MatchId" text NULL
);

CREATE INDEX IF NOT EXISTS "IX_lobbies_HostUserId" ON lobbies("HostUserId");
CREATE INDEX IF NOT EXISTS "IX_lobbies_Status" ON lobbies("Status");

CREATE TABLE IF NOT EXISTS lobby_players (
    "LobbyId" text NOT NULL,
    "UserId" text NOT NULL,
    "SeatIndex" integer NOT NULL,
    "DisplayName" text NOT NULL,
    "DeckId" text NULL,
    "SelectedBattlefieldIdsJson" jsonb NOT NULL,
    "TeamId" integer NULL,
    "IsReady" boolean NOT NULL,
    "JoinedAt" timestamptz NOT NULL,
    "UpdatedAt" timestamptz NOT NULL,
    PRIMARY KEY ("LobbyId", "UserId")
);

CREATE INDEX IF NOT EXISTS "IX_lobby_players_LobbyId" ON lobby_players("LobbyId");
CREATE INDEX IF NOT EXISTS "IX_lobby_players_UserId" ON lobby_players("UserId");

CREATE TABLE IF NOT EXISTS user_active_decks (
    "UserId" text NOT NULL,
    "DeckId" text NOT NULL,
    "AddedAt" timestamptz NOT NULL,
    PRIMARY KEY ("UserId", "DeckId")
);

CREATE INDEX IF NOT EXISTS "IX_user_active_decks_DeckId" ON user_active_decks("DeckId");

-- Card effect step storage (see 002_card_effect_steps.sql).
ALTER TABLE cards ADD COLUMN IF NOT EXISTS "EffectsJson" jsonb NOT NULL DEFAULT '[]'::jsonb;

-- Full current card catalog (1,048 rows), including the hand-authored effects from the
-- card-effects implementation pass: EffectType/EffectAmount for single-instruction cards,
-- EffectsJson for multi-step cards (e.g. "Deal 4 to a unit. Draw 1."). Upserts by "Id" so this
-- is safe to re-run against a database that already has older card rows.

